UPDATE words SET example_en_2 = 'The etiology of this disease is not yet fully understood.', example_ko_2 = '이 질병의 원인은 아직 완전히 밝혀지지 않았어요.', example_en_3 = 'Researchers are investigating the etiology of the syndrome.', example_ko_3 = '연구자들이 이 증후군의 원인을 조사하고 있어요.', example_en_4 = 'Understanding the etiology helps guide treatment strategies.', example_ko_4 = '원인을 이해하면 치료 전략을 수립하는 데 도움이 돼요.', example_en_5 = 'The etiology may involve both genetic and environmental factors.', example_ko_5 = '원인에는 유전적 요인과 환경적 요인이 모두 관여할 수 있어요.' WHERE id = 'w_health_C1_01';
UPDATE words SET example_en_2 = 'Comorbidity complicates treatment planning significantly.', example_ko_2 = '동반 질환은 치료 계획을 크게 복잡하게 만들어요.', example_en_3 = 'His comorbidity included both hypertension and diabetes.', example_ko_3 = '그의 동반 질환에는 고혈압과 당뇨병이 모두 포함됐어요.', example_en_4 = 'Patients with comorbidity often require specialist referral.', example_ko_4 = '동반 질환이 있는 환자는 종종 전문의 의뢰가 필요해요.', example_en_5 = 'Researchers studied the impact of comorbidity on recovery outcomes.', example_ko_5 = '연구자들이 동반 질환이 회복 결과에 미치는 영향을 연구했어요.' WHERE id = 'w_health_C1_02';
UPDATE words SET example_en_2 = 'Pharmacology explores how drugs interact with the body.', example_ko_2 = '약리학은 약물이 신체와 어떻게 상호 작용하는지 탐구해요.', example_en_3 = 'She studied pharmacology before becoming a clinical researcher.', example_ko_3 = '그녀는 임상 연구원이 되기 전에 약리학을 공부했어요.', example_en_4 = 'Advances in pharmacology have led to more effective treatments.', example_ko_4 = '약리학의 발전으로 더 효과적인 치료법이 생겼어요.', example_en_5 = 'The pharmacology of the new drug is well understood.', example_ko_5 = '새 약물의 약리학은 잘 이해되고 있어요.' WHERE id = 'w_health_C1_03';
UPDATE words SET example_en_2 = 'Endocrinology focuses on hormonal disorders.', example_ko_2 = '내분비학은 호르몬 장애에 집중해요.', example_en_3 = 'He trained in endocrinology to treat thyroid conditions.', example_ko_3 = '그는 갑상선 질환을 치료하기 위해 내분비학을 전공했어요.', example_en_4 = 'She was referred to the endocrinology department.', example_ko_4 = '그녀는 내분비학과로 의뢰됐어요.', example_en_5 = 'Endocrinology and metabolism are closely linked fields.', example_ko_5 = '내분비학과 신진대사는 밀접하게 연결된 분야예요.' WHERE id = 'w_health_C1_04';
UPDATE words SET example_en_2 = 'She specializes in neurology with a focus on movement disorders.', example_ko_2 = '그녀는 운동 장애에 초점을 맞춘 신경학을 전문으로 해요.', example_en_3 = 'Neurology covers conditions like epilepsy and multiple sclerosis.', example_ko_3 = '신경학은 간질과 다발성 경화증 같은 질환을 다뤄요.', example_en_4 = 'He was admitted to the neurology ward for observation.', example_ko_4 = '그는 관찰을 위해 신경학과 병동에 입원했어요.', example_en_5 = 'Neurology is one of the most complex medical specialties.', example_ko_5 = '신경학은 가장 복잡한 의학 전문 분야 중 하나예요.' WHERE id = 'w_health_C1_05';
