UPDATE words SET example_en_2 = 'Teratogenic drugs must not be taken during pregnancy.', example_ko_2 = '최기형성 약물은 임신 중에 복용해서는 안 돼요.', example_en_3 = 'The compound was found to be teratogenic in animal trials.', example_ko_3 = '동물 실험에서 이 화합물이 최기형성을 가진 것으로 나타났어요.', example_en_4 = 'Doctors screen for teratogenic risk before prescribing to pregnant patients.', example_ko_4 = '의사들은 임산부에게 처방하기 전에 최기형성 위험을 확인해요.', example_en_5 = 'The teratogenic effects were observed in the first trimester.', example_ko_5 = '최기형성 효과는 임신 초기에 관찰됐어요.' WHERE id = 'w_health_C2_05';
UPDATE words SET example_en_2 = 'The sequelae of the stroke included partial paralysis.', example_ko_2 = '뇌졸중의 후유증에는 부분 마비가 포함됐어요.', example_en_3 = 'Long-term sequelae can persist years after the initial illness.', example_ko_3 = '장기 후유증은 초기 질환 수년 후에도 지속될 수 있어요.', example_en_4 = 'Patients were monitored for sequelae following the infection.', example_ko_4 = '환자들은 감염 후 후유증 여부를 모니터링받았어요.', example_en_5 = 'Cognitive sequelae were reported in some recovered patients.', example_ko_5 = '일부 회복 환자에서 인지적 후유증이 보고됐어요.' WHERE id = 'w_health_C2_06';
