UPDATE words SET example_en_2 = 'Hyponatremia can cause confusion and seizures if severe.', example_ko_2 = '저나트륨혈증이 심하면 혼란과 발작을 유발할 수 있어요.', example_en_3 = 'She developed hyponatremia after drinking excessive amounts of water.', example_ko_3 = '그녀는 과도한 물을 마신 후 저나트륨혈증이 생겼어요.', example_en_4 = 'Treatment of hyponatremia requires careful correction of sodium levels.', example_ko_4 = '저나트륨혈증 치료에는 나트륨 수치를 신중하게 교정하는 것이 필요해요.', example_en_5 = 'Hyponatremia is a common electrolyte disorder in hospitalized patients.', example_ko_5 = '저나트륨혈증은 입원 환자에서 흔한 전해질 장애예요.' WHERE id = 'w_health_C2_20';
