UPDATE words SET example_en_2 = 'The compound was found to be mutagenic in cell culture tests.', example_ko_2 = '이 화합물은 세포 배양 실험에서 변이원성이 있는 것으로 밝혀졌어요.', example_en_3 = 'Mutagenic substances can alter DNA and increase cancer risk.', example_ko_3 = '변이원성 물질은 DNA를 변형시켜 암 위험을 높일 수 있어요.', example_en_4 = 'Regulatory agencies classify chemicals by their mutagenic potential.', example_ko_4 = '규제 기관은 화학 물질을 변이원성 가능성에 따라 분류해요.', example_en_5 = 'Avoiding mutagenic chemicals in the workplace protects long-term health.', example_ko_5 = '직장에서 변이원성 화학 물질을 피하면 장기적인 건강을 보호해요.' WHERE id = 'w_health_C2_22';
